const express = require('express');
const { Pool } = require('pg');
require('dotenv').config();

// --- Database Configuration ---
// Uses a dedicated application user with limited privileges, NOT a superuser.
const pool = new Pool({
  user: process.env.DB_USER,         // e.g., 'app_service' — NOT 'postgres'
  host: process.env.DB_HOST,         // e.g., 'localhost'
  database: process.env.DB_NAME,     // e.g., 'myappdb'
  password: process.env.DB_PASSWORD, // strong, unique password
  port: parseInt(process.env.DB_PORT, 10) || 5432,
  max: 20,
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 5000,
  ssl: process.env.DB_SSL === 'true' ? { rejectUnauthorized: true } : false,
});

pool.on('error', (err) => {
  console.error('Unexpected idle client error:', err);
  process.exit(-1);
});

// --- Verify Connection and Confirm Non-Superuser ---
async function verifyConnection() {
  const client = await pool.connect();
  try {
    // Verify we are NOT connected as a superuser
    const result = await client.query('SELECT current_user, usesuper FROM pg_user WHERE usename = current_user');
    const { current_user: currentUser, usesuper } = result.rows[0];

    if (usesuper) {
      console.error('╔══════════════════════════════════════════════════════════╗');
      console.error('║  SECURITY ERROR: Connected as a PostgreSQL superuser!   ║');
      console.error('║  Create a dedicated app user with limited privileges.   ║');
      console.error('║  See setup-database.sql instructions in this file.      ║');
      console.error('╚══════════════════════════════════════════════════════════╝');
      process.exit(1);
    }

    console.log(`Database connected successfully as user: "${currentUser}" (superuser: ${usesuper})`);
  } finally {
    client.release();
  }
}

// --- Database Helper ---
async function query(text, params) {
  const start = Date.now();
  try {
    const result = await pool.query(text, params);
    const duration = Date.now() - start;
    console.log('Query executed', { text: text.substring(0, 80), duration: `${duration}ms`, rows: result.rowCount });
    return result;
  } catch (error) {
    console.error('Query error:', { text: text.substring(0, 80), error: error.message });
    throw error;
  }
}

async function getClient() {
  return pool.connect();
}

