// --- Products Service ---
class ProductsService {
  async create({ name, description, price, stockQuantity, categoryId, createdBy }) {
    const result = await query(
      `INSERT INTO products (name, description, price, stock_quantity, category_id, created_by)
       VALUES ($1, $2, $3, $4, $5, $6) RETURNING *`,
      [name, description, price, stockQuantity || 0, categoryId, createdBy]
    );
    return result.rows[0];
  }

  async findById(id) {
    const result = await query(
      `SELECT p.*, c.name AS category_name,
              u.first_name || ' ' || u.last_name AS created_by_name
       FROM products p
       LEFT JOIN categories c ON p.category_id = c.id
       LEFT JOIN users u ON p.created_by = u.id
       WHERE p.id = $1`,
      [id]
    );
    return result.rows[0] || null;
  }

  async findAll({ limit = 20, offset = 0, categoryId = null, isAvailable = null, search = null } = {}) {
    let queryText = `
      SELECT p.*, c.name AS category_name
      FROM products p
      LEFT JOIN categories c ON p.category_id = c.id
      WHERE 1=1
    `;
    const params = [];

    if (categoryId !== null) {
      params.push(categoryId);
      queryText += ` AND p.category_id = $${params.length}`;
    }
    if (isAvailable !== null) {
      params.push(isAvailable);
      queryText += ` AND p.is_available = $${params.length}`;
    }
    if (search) {
      params.push(`%${search}%`);
      queryText += ` AND (p.name ILIKE $${params.length} OR p.description ILIKE $${params.length})`;
    }

    const countParams = [...params];
    const countQuery = queryText.replace(/SELECT .* FROM/, 'SELECT COUNT(*) FROM');

    queryText += ` ORDER BY p.created_at DESC`;
    params.push(limit);
    queryText += ` LIMIT $${params.length}`;
    params.push(offset);
    queryText += ` OFFSET $${params.length}`;

    const [result, countResult] = await Promise.all([
      query(queryText, params),
      query(countQuery, countParams),
    ]);

    return { products: result.rows, total: parseInt(countResult.rows[0].count, 10) };
  }

  async update(id, { name, description, price, stockQuantity, categoryId, isAvailable }) {
    const fields = [];
    const params = [];
    let paramCount = 0;

    if (name !== undefined) { paramCount++; fields.push(`name = $${paramCount}`); params.push(name); }
    if (description !== undefined) { paramCount++; fields.push(`description = $${paramCount}`); params.push(description); }
    if (price !== undefined) { paramCount++; fields.push(`price = $${paramCount}`); params.push(price); }
    if (stockQuantity !== undefined) { paramCount++; fields.push(`stock_quantity = $${paramCount}`); params.push(stockQuantity); }
    if (categoryId !== undefined) { paramCount++; fields.push(`category_id = $${paramCount}`); params.push(categoryId); }
    if (isAvailable !== undefined) { paramCount++; fields.push(`is_available = $${paramCount}`); params.push(isAvailable); }

    if (fields.length === 0) return this.findById(id);

    fields.push(`updated_at = NOW()`);
    paramCount++;
    params.push(id);

    const result = await query(
      `UPDATE products SET ${fields.join(', ')} WHERE id = $${paramCount} RETURNING *`,
      params
    );
    return result.rows[0] || null;
  }

  async delete(id) {
    const result = await query(`DELETE FROM products WHERE id = $1 RETURNING id`, [id]);
    return result.rowCount > 0;
  }
}

// --- Orders Service ---
class OrdersService {
  async create({ userId, shippingAddress, items }) {
    const client = await getClient();
    try {
      await client.query('BEGIN');

      // Validate stock and compute totals
      let totalAmount = 0;
      const validatedItems = [];

      for (const item of items) {
        const productResult = await client.query(
          `SELECT id, name, price, stock_quantity, is_available FROM products WHERE id = $1 FOR UPDATE`,
          [item.productId]
        );

        if (productResult.rows.length === 0) {
          throw new Error(`Product with ID ${item.productId} not found`);
        }

        const product = productResult.rows[0];

        if (!product.is_available) {
          throw new Error(`Product "${product.name}" is not available`);
        }
        if (product.stock_quantity < item.quantity) {
          throw new Error(`Insufficient stock for "${product.name}". Available: ${product.stock_quantity}, requested: ${item.quantity}`);
        }

        totalAmount += parseFloat(product.price) * item.quantity;
        validatedItems.push({
          productId: product.id,
          quantity: item.quantity,
          unitPrice: product.price,
        });

        // Decrement stock
        await client.query(
          `UPDATE products SET stock_quantity = stock_quantity - $1, updated_at = NOW() WHERE id = $2`,
          [item.quantity, product.id]
        );
      }

      // Create order
      const orderResult = await client.query(
        `INSERT INTO orders (user_id, total_amount, shipping_address)
         VALUES ($1, $2, $3) RETURNING *`,
        [userId, totalAmount.toFixed(2), shippingAddress]
      );
      const order = orderResult.rows[0];

      // Create order items
      for (const item of validatedItems) {
        await client.query(
          `INSERT INTO order_items (order_id, product_id, quantity, unit_price)
           VALUES ($1, $2, $3, $4)`,
          [order.id, item.productId, item.quantity, item.unitPrice]
        );
      }

      await client.query('COMMIT');

      return this.findById(order.id);
    } catch (error) {
      await client.query('ROLLBACK');
      throw error;
    } finally {
      client.release();
    }
  }

  async findById(id) {
    const orderResult = await query(
      `SELECT o.*, u.email AS user_email,
              u.first_name || ' ' || u.last_name AS user_name
       FROM orders o
       JOIN users u ON o.user_id = u.id
       WHERE o.id = $1`,
      [id]
    );

    if (orderResult.rows.length === 0) return null;

    const itemsResult = await query(
      `SELECT oi.*, p.name AS product_name
       FROM order_items oi
       JOIN products p ON oi.product_id = p.id
       WHERE oi.order_id = $1
       ORDER BY oi.id`,
      [id]
    );

    return { ...orderResult.rows[0], items: itemsResult.rows };
  }

  async findByUserId(userId, { limit = 20, offset = 0 } = {}) {
    const result = await query(
      `SELECT o.*, (SELECT COUNT(*) FROM order_items WHERE order_id = o.id) AS item_count
       FROM orders o
       WHERE o.user_id = $1
       ORDER BY o.created_at DESC
       LIMIT $2 OFFSET $3`,
      [userId, limit, offset]
    );

    const countResult = await query(
      `SELECT COUNT(*) FROM orders WHERE user_id = $1`,
      [userId]
    );

    return { orders: result.rows, total: parseInt(countResult.rows[0].count, 10) };
  }

  async findAll({ limit = 20, offset = 0, status = null } = {}) {
    let queryText = `
      SELECT o.*, u.email AS user_email,
             u.first_name || ' ' || u.last_name AS user_name,
             (SELECT COUNT(*) FROM order_items WHERE order_id = o.id) AS item_count
      FROM orders o
      JOIN users u ON o.user_id = u.id
    `;
    const params = [];

    if (status) {
      params.push(status);
      queryText += ` WHERE o.status = $${params.length}`;
    }

    queryText += ` ORDER BY o.created_at DESC`;
    params.push(limit);
    queryText += ` LIMIT $${params.length}`;
    params.push(offset);
    queryText += ` OFFSET $${params.length}`;

    const result = await query(queryText, params);

    const countResult = await query(
      `SELECT COUNT(*) FROM orders ${status ? 'WHERE status = $1' : ''}`,
      status ? [status] : []
    );

    return { orders: result.rows, total: parseInt(countResult.rows[0].count, 10) };
  }

  async updateStatus(id, status) {
    const result = await query(
      `UPDATE orders SET status = $1, updated_at = NOW() WHERE id = $2 RETURNING *`,
      [status, id]
    );
    return result.rows[0] || null;
  }

  async cancel(id) {
    const client = await getClient();
    try {
      await client.query('BEGIN');

      const orderResult = await client.query(
        `SELECT * FROM orders WHERE id = $1 FOR UPDATE`,
        [id]
      );

      if (orderResult.rows.length === 0) throw new Error('Order not found');
      if (orderResult.rows[0].status === 'cancelled') throw new Error('Order is already cancelled');
      if (['shipped', 'delivered'].includes(orderResult.rows[0].status)) {
        throw new Error('Cannot cancel a shipped or delivered order');
      }

      // Restore stock
      const itemsResult = await client.query(
        `SELECT product_id, quantity FROM order_items WHERE order_id = $1`,
        [id]
      );

      for (const item of itemsResult.rows) {
        await client.query(
          `UPDATE products SET stock_quantity = stock_quantity + $1, updated_at = NOW() WHERE id = $2`,
          [item.quantity, item.product_id]
        );
      }

      await client.query(
        `UPDATE orders SET status = 'cancelled', updated_at = NOW() WHERE id = $1`,
        [id]
      );

      await client.query('COMMIT');
      return this.findById(id);
    } catch (error) {
      await client.query('ROLLBACK');
      throw error;
    } finally {
      client.release();
    }
  }

  async delete(id) {
    const result = await query(`DELETE FROM orders WHERE id = $1 RETURNING id`, [id]);
    return result.rowCount > 0;
  }
}

