const app = express();
app.use(express.json());

const usersService = new UsersService();
const categoriesService = new CategoriesService();
const productsService = new ProductsService();
const ordersService = new OrdersService();

// Error handler middleware
function asyncHandler(fn) {
  return (req, res, next) => {
    Promise.resolve(fn(req, res, next)).catch(next);
  };
}

// --- Health Check ---
app.get('/api/health', asyncHandler(async (req, res) => {
  const result = await query('SELECT NOW() AS server_time, current_user');
  res.json({ status: 'healthy', database: result.rows[0] });
}));

// --- Users Routes ---
app.post('/api/users', asyncHandler(async (req, res) => {
  const { email, firstName, lastName, passwordHash } = req.body;
  if (!email || !firstName || !lastName || !passwordHash) {
    return res.status(400).json({ error: 'Missing required fields: email, firstName, lastName, passwordHash' });
  }
  const user = await usersService.create({ email, firstName, lastName, passwordHash });
  res.status(201).json(user);
}));

app.get('/api/users', asyncHandler(async (req, res) => {
  const { limit, offset, isActive } = req.query;
  const result = await usersService.findAll({
    limit: parseInt(limit, 10) || 20,
    offset: parseInt(offset, 10) || 0,
    isActive: isActive !== undefined ? isActive === 'true' : null,
  });
  res.json(result);
}));

app.get('/api/users/:id', asyncHandler(async (req, res) => {
  const user = await usersService.findById(parseInt(req.params.id, 10));
  if (!user) return res.status(404).json({ error: 'User not found' });
  res.json(user);
}));

app.put('/api/users/:id', asyncHandler(async (req, res) => {
  const { email, firstName, lastName, isActive } = req.body;
  const user = await usersService.update(parseInt(req.params.id, 10), { email, firstName, lastName, isActive });
  if (!user) return res.status(404).json({ error: 'User not found' });
  res.json(user);
}));

app.delete('/api/users/:id', asyncHandler(async (req, res) => {
  const deleted = await usersService.delete(parseInt(req.params.id, 10));
  if (!deleted) return res.status(404).json({ error: 'User not found' });
  res.status(204).send();
}));

