app.get('/api/products/:id', asyncHandler(async (req, res) => {
  const product = await productsService.findById(parseInt(req.params.id, 10));
  if (!product) return res.status(404).json({ error: 'Product not found' });
  res.json(product);
}));

app.put('/api/products/:id', asyncHandler(async (req, res) => {
  const { name, description, price, stockQuantity, categoryId, isAvailable } = req.body;
  const product = await productsService.update(parseInt(req.params.id, 10), {
    name, description, price, stockQuantity, categoryId, isAvailable,
  });
  if (!product) return res.status(404).json({ error: 'Product not found' });
  res.json(product);
}));

app.delete('/api/products/:id', asyncHandler(async (req, res) => {
  const deleted = await productsService.delete(parseInt(req.params.id, 10));
  if (!deleted) return res.status(404).json({ error: 'Product not found' });
  res.status(204).send();
}));

// --- Orders Routes ---
app.post('/api/orders', asyncHandler(async (req, res) => {
  const { userId, shippingAddress, items } = req.body;
  if (!userId || !items || !Array.isArray(items) || items.length === 0) {
    return res.status(400).json({ error: 'Missing required fields: userId, items (non-empty array)' });
  }
  for (const item of items) {
    if (!item.productId || !item.quantity || item.quantity < 1) {
      return res.status(400).json({ error: 'Each item must have productId and quantity (>= 1)' });
    }
  }
  const order = await ordersService.create({ userId, shippingAddress, items });
  res.status(201).json(order);
}));

app.get('/api/orders', asyncHandler(async (req, res) => {
  const { limit, offset, status } = req.query;
  const result = await ordersService.findAll({
    limit: parseInt(limit, 10) || 20,
    offset: parseInt(offset, 10) || 0,
    status: status || null,
  });
  res.json(result);
}));

app.get('/api/orders/:id', asyncHandler(async (req, res) => {
  const order = await ordersService.findById(parseInt(req.params.id, 10));
  if (!order) return res.status(404).json({ error: 'Order not found' });
  res.json(order);
}));

app.get('/api/users/:userId/orders', asyncHandler(async (req, res) => {
  const { limit, offset } = req.query;
  const result = await ordersService.findByUserId(parseInt(req.params.userId, 10), {
    limit: parseInt(limit, 10) || 20,
    offset: parseInt(offset, 10) || 0,
  });
  res.json(result);
}));

app.patch('/api/orders/:id/status', asyncHandler(async (req, res) => {
  const { status } = req.body;
  const validStatuses = ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'];
  if (!status || !validStatuses.includes(status)) {
    return res.status(400).json({ error: `Status must be one of: ${validStatuses.join(', ')}` });
  }
  if (status === 'cancelled') {
    const order = await ordersService.cancel(parseInt(req.params.id, 10));
    return res.json(order);
  }
  const order = await ordersService.updateStatus(parseInt(req.params.id, 10), status);
  if (!order) return res.status(404).json({ error: 'Order not found' });
  res.json(order);
}));

app.delete('/api/orders/:id', asyncHandler(async (req, res) => {
  const deleted = await ordersService.delete(parseInt(req.params.id, 10));
  if (!deleted) return res.status(404).json({ error: 'Order not found' });
  res.status(204).send();
}));

// --- Global Error Handler ---
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);

  if (err.code === '23505') {
    return res.status(409).json({ error: 'Duplicate entry. A record with this value already exists.' });
  }
  if (err.code === '23503') {
    return res.status(400).json({ error: 'Referenced record does not exist.' });
  }
  if (err.code === '23514') {
    return res.status(400).json({ error: 'Value violates a constraint check.' });
  }

  res.status(err.statusCode || 500).json({
    error: err.message || 'Internal server error',
  });
});

// --- Start Server ---
const PORT = process.env.PORT || 3000;

async function startServer() {
  try {
    await verifyConnection();
    await initializeSchema();

    app.listen(PORT, () => {
      console.log(`API server running on port ${PORT}`);
      console.log(`Health check: http://localhost:${PORT}/api/health`);
    });
  } catch (error) {
    console.error('Failed to start server:', error);
    process.exit(1);
  }
}

// Graceful shutdown
async function shutdown(signal) {
  console.log(`${signal} received. Shutting down gracefully...`);
  await pool.end();
  console.log('Database pool closed.');
  process.exit(0);
}

process.on('SIGTERM', () => shutdown('SIGTERM'));
process.on('SIGINT', () => shutdown('SIGINT'));

startServer();

module.exports = { app, pool };